var val = Services.getValue(AttendCostAmt.dataBinding);
var max = 999999.99;
var err = validateCurrencyValue(val, max);
if( null == err )
{	Services.setValue(AttendCostAmt.dataBinding, WPU.formatToTwoDP(val));
}
return err;

